// isSafeScript performs conservative validation to reject obviously dangerous scripts.
// This is not a full JavaScript parser, but it significantly reduces risk by allowing
// simple filter expressions while blocking common abuse primitives.
func isSafeScript(script string) bool {
	if len(script) > 1024 {
		return false
	}

	disallowed := []string{
		";",
		"{",
		"}",
		"function",
		"=>",
		"while",
		"for",
		"do",
		"switch",
		"try",
		"catch",
		"eval",
		"Function",
		"constructor",
		"prototype",
		"__proto__",
		"this",
		"global",
		"window",
		"process",
