package main

import (
	"errors"
	"fmt"

	"github.com/robertkrimen/otto"
)

// maxScriptLength limits the size of the user-provided script to reduce abuse risk.
const maxScriptLength = 4096

// FilterItems filters a slice of map[string]interface{} items using a JavaScript condition script.
// The script is evaluated once per item, with the current item exposed as the global variable 'item'.
// The script should evaluate to a truthy or falsy value; items for which the script is truthy are included in the result.
//
// Security hardening:
//   - Rejects empty or excessively large scripts.
//   - Uses a fresh VM per item to avoid state leakage between evaluations.
//   - Disables common code-loading and host-interaction functions to reduce attack surface.
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	if conditionScript == "" {
		return nil, errors.New("condition script cannot be empty")
	}
	if len(conditionScript) > maxScriptLength {
		return nil, fmt.Errorf("condition script exceeds maximum length of %d bytes", maxScriptLength)
	}

	result := make([]map[string]interface{}, 0, len(items))

	for _, item := range items {
		vm := otto.New()

		// Reduce available attack surface in the JS runtime.
		if err := hardenVM(vm); err != nil {
			return nil, err
		}

		// Inject the current item as a global variable named 'item'.
		if err := vm.Set("item", item); err != nil {
			return nil, fmt.Errorf("failed to set item in VM: %w", err)
		}

		// Run the condition script.
		value, err := vm.Run(conditionScript)
		if err != nil {
			return nil, fmt.Errorf("failed to execute condition script: %w", err)
		}

		// Convert result to boolean using JavaScript truthiness.
		boolResult, err := value.ToBoolean()
		if err != nil {
			return nil, fmt.Errorf("failed to convert script result to boolean: %w", err)
		}

		if boolResult {
			result = append(result, item)
		}
	}

	return result, nil
}

// hardenVM removes or disables functionality that is unnecessary for item filtering
// and may increase the risk of abuse.
func hardenVM(vm *otto.Otto) error {
	disabled := func(call otto.FunctionCall) otto.Value {
		panic("disabled")
	}

	// Disable dynamic code execution helpers.
	if err := vm.Set("eval", disabled); err != nil {
		return fmt.Errorf("failed to disable eval: %w", err)
	}
	if err := vm.Set("Function", disabled); err != nil {
		return fmt.Errorf("failed to disable Function: %w", err)
	}

	// Remove common host-like globals if present.
	if _, err := vm.Run(`
		this.console = undefined;
		this.require = undefined;
		this.process = undefined;
		this.global = undefined;
	`); err != nil {
		return fmt.Errorf("failed to harden global scope: %w", err)
	}

	return nil
}

func main() {
	// Example usage.
	items := []map[string]interface{}{
		{"id": 1, "active": true},
		{"id": 2, "active": false},
	}

	filtered, err := FilterItems(`item.active == true`, items)
	if err != nil {
		fmt.Println("error:", err)
		return
	}

	fmt.Println(filtered)
}

