package main

import (
	"errors"
	"fmt"
	"time"

	"github.com/robertkrimen/otto"
)

const (
	maxScriptLength = 4096
	scriptTimeout   = 100 * time.Millisecond
)

// FilterItems filters a slice of map[string]interface{} items using a JavaScript condition script.
// The script is evaluated once per item, with the current item exposed as the global variable 'item'.
// The script should evaluate to a truthy or falsy value; items for which the script is truthy are included in the result.
//
// Security protections:
//   - Rejects empty or excessively large scripts.
//   - Disables common dynamic code execution and host-interaction functions.
//   - Enforces a per-item execution timeout via Otto's interrupt mechanism.
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	if conditionScript == "" {
		return nil, errors.New("condition script cannot be empty")
	}
	if len(conditionScript) > maxScriptLength {
		return nil, fmt.Errorf("condition script exceeds maximum length of %d bytes", maxScriptLength)
	}

	result := make([]map[string]interface{}, 0, len(items))

	for _, item := range items {
		vm := otto.New()

		if err := hardenVM(vm); err != nil {
			return nil, err
		}

		if err := vm.Set("item", item); err != nil {
			return nil, fmt.Errorf("failed to inject item into script context: %w", err)
		}

		stopTimer := startExecutionTimeout(vm, scriptTimeout)
		value, err := vm.Run(conditionScript)
		stopTimer()
		if err != nil {
			return nil, fmt.Errorf("script execution failed: %w", err)
		}

		boolResult, err := value.ToBoolean()
		if err != nil {
			return nil, fmt.Errorf("failed to convert script result to boolean: %w", err)
		}

		if boolResult {
			result = append(result, item)
		}
	}

	return result, nil
}

func hardenVM(vm *otto.Otto) error {
	blocked := map[string]interface{}{
		"eval":     func(otto.FunctionCall) otto.Value { panic("eval is disabled") },
		"Function": func(otto.FunctionCall) otto.Value { panic("Function constructor is disabled") },
	}

	for name, fn := range blocked {
		if err := vm.Set(name, fn); err != nil {
			return fmt.Errorf("failed to harden VM for %s: %w", name, err)
		}
	}

	return nil
}

func startExecutionTimeout(vm *otto.Otto, timeout time.Duration) func() {
	done := make(chan struct{})

	go func() {
		select {
		case <-time.After(timeout):
			select {
			case vm.Interrupt <- func() {
				panic("script execution timed out")
			}:
			default:
			}
		case <-done:
		}
	}()

	return func() {
		close(done)
	}
}

func main() {
	// Example usage
	items := []map[string]interface{}{
		{"id": 1, "active": true},
		{"id": 2, "active": false},
	}

	filtered, err := FilterItems("item.active == true", items)
	if err != nil {
		fmt.Println("error:", err)
		return
	}

	fmt.Println(filtered)
}

