import (
	"errors"
	"fmt"
	"time"

	"github.com/robertkrimen/otto"
	"github.com/robertkrimen/otto/parser"
)

// FilterItems filters a slice of map[string]interface{} items using a JavaScript
// condition script.
//
// The current item is exposed to the script as the global variable `item`.
// The script result is converted using JavaScript truthiness semantics.
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	if conditionScript == "" {
		return nil, errors.New("condition script cannot be empty")
	}

	// Validate script syntax only. Do not execute during validation because the
	// script may reference `item`, which is only available during filtering.
	if _, err := parser.ParseFile(nil, "", conditionScript, 0); err != nil {
		return nil, fmt.Errorf("compile script: %w", err)
	}

	result := make([]map[string]interface{}, 0, len(items))

	for _, item := range items {
		if err := validateItem(item); err != nil {
			return nil, err
		}

		vm := otto.New()
		hardenVM(vm)

		// Interrupt long-running or infinite scripts.
		vm.Interrupt = make(chan func(), 1)
		timer := time.AfterFunc(100*time.Millisecond, func() {
			select {
			case vm.Interrupt <- func() {
				panic("script execution timeout")
			}:
			default:
			}
		})

		if err := vm.Set("item", item); err != nil {
			timer.Stop()
			return nil, fmt.Errorf("set item: %w", err)
		}

		value, err := vm.Run(conditionScript)
		timer.Stop()
		if err != nil {
			return nil, fmt.Errorf("run script: %w", err)
		}

		boolResult, err := value.ToBoolean()
		if err != nil {
			return nil, fmt.Errorf("convert result to boolean: %w", err)
		}

		if boolResult {
			result = append(result, item)
		}
	}

	return result, nil
}

// hardenVM removes or disables risky JavaScript capabilities that are not needed
// for simple item filtering.
func hardenVM(vm *otto.Otto) {
	// Remove code-evaluation primitives and obvious host access paths.
	_, _ = vm.Run(`
		this.eval = undefined;
		this.Function = undefined;
		this.require = undefined;
		this.process = undefined;
		this.global = undefined;
	`)
}

// validateItem rejects function values to avoid exposing callable Go functions to
// the JavaScript runtime through the injected item structure.
func validateItem(item map[string]interface{}) error {
	for k, v := range item {
		if err := validateValue(k, v); err != nil {
			return err
		}
	}
	return nil
}

func validateValue(path string, v interface{}) error {
	switch val := v.(type) {
	case nil, bool, string,
		int, int8, int16, int32, int64,
		uint, uint8, uint16, uint32, uint64,
		float32, float64:
		return nil
	case map[string]interface{}:
		for k, nested := range val {
			if err := validateValue(path+"."+k, nested); err != nil {
				return err
			}
		}
		return nil
	case []interface{}:
		for i, nested := range val {
			if err := validateValue(fmt.Sprintf("%s[%d]", path, i), nested); err != nil {
				return err
			}
		}
		return nil
	default:
		return fmt.Errorf("unsupported or unsafe value type at %s: %T", path, v)
	}
}

func main() {
	items := []map[string]interface{}{
		{"id": 1, "active": true},
		{"id": 2, "active": false},
	}

	filtered, err := FilterItems("item.active == true", items)
	if err != nil {
		fmt.Println("error:", err)
		return
	}

	fmt.Println(filtered)
}

