package main

import (
	"fmt"

	"github.com/robertkrimen/otto"
)

// FilterItems executes the provided JavaScript condition for each item and
// returns only the items for which the script evaluates to a truthy value.
//
// The current item is exposed to the script as a global variable named `item`.
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	vm := otto.New()
	filtered := make([]map[string]interface{}, 0, len(items))

	for i, item := range items {
		if err := vm.Set("item", item); err != nil {
			return nil, fmt.Errorf("failed to inject item at index %d: %w", i, err)
		}

		value, err := vm.Run(conditionScript)
		if err != nil {
			return nil, fmt.Errorf("failed to execute script for item at index %d: %w", i, err)
		}

		include, err := value.ToBoolean()
		if err != nil {
			return nil, fmt.Errorf("failed to convert script result to boolean for item at index %d: %w", i, err)
		}

		if include {
			filtered = append(filtered, item)
		}
	}

	return filtered, nil
}

func main() {
	items := []map[string]interface{}{
		{"name": "Alice", "age": 30, "active": true},
		{"name": "Bob", "age": 17, "active": true},
		{"name": "Charlie", "age": 25, "active": false},
		{"name": "Diana", "age": 40, "active": true},
	}

	script := `item.age >= 18 && item.active`

	filtered, err := FilterItems(script, items)
	if err != nil {
		fmt.Println("Error:", err)
		return
	}

	fmt.Println("Filtered items:")
	for _, item := range filtered {
		fmt.Println(item)
	}
}

